# -*- coding: utf-8 -*-# ==============================================================# Departamento de Ingenieria Mecanica - Universidad de Chile# Trabajo de Memoria de Titulo:# "Implementacion de algoritmos de reconocimiento de objetos#  para la identificacion de fallas en correas transportadoras"# Autor: Fernando N.# --------------------------------------------------------------# Archivo: check_environment.py# Descripcion: Script de validacion de entorno para PyTorch.# Version objetivo: ROCm 7.2.0 (Windows) + PyTorch 2.9.1 (Preview)# Fecha actualizacion: 09/03/2026# ==============================================================import torchimport sysimport platformimport subprocessdef print_section(title):    print("\n" + "=" * 60)    print(f" {title}")    print("=" * 60)def main():    print_section("1. DIAGNOSTICO DEL SISTEMA")    print(f"Sistema Operativo : {platform.system()} {platform.release()}")    print(f"Arquitectura      : {platform.machine()}")    print(f"Version de Python : {sys.version.split()[0]}")    print_section("2. VERIFICACION DE PYTORCH")    print(f"Version instalada : {torch.__version__}")    # Verificacion de build especifico    if "rocmsdk" not in torch.__version__:        print("[ADVERTENCIA]: La version instalada no parece corresponder al build de ROCm SDK.")    else:        print("[OK] Build correcto detectado (rocmsdk).")    # Deteccion de Backend    cuda_ok = torch.cuda.is_available()    hip_version = getattr(torch.version, 'hip', 'No detectado')    print(f"Soporte CUDA/ROCm : {'DISPONIBLE' if cuda_ok else 'NO DISPONIBLE'}")    print(f"Version HIP interna: {hip_version}")    if not cuda_ok:        print("\n[CRITICO]: PyTorch no detecta la GPU. Verifique la instalacion del SDK de ROCm 7.2.0.")        print("   Asegurese de haber reiniciado la terminal despues de la instalacion.")        return    device_id = torch.cuda.current_device()    device_name = torch.cuda.get_device_name(device_id)    print(f"Dispositivo activo: {device_name} (ID: {device_id})")    print_section("3. PRUEBA DE TENSOR (TEST DE ESTRES SIMPLE)")    try:        device = torch.device('cuda')        # Creacion de tensores        print("Allocando tensores en VRAM...", end=" ")        x = torch.randn(2048, 2048, device=device)        y = torch.randn(2048, 2048, device=device)        print("OK")        # Operacion matematica (Matrix Multiplication)        print("Ejecutando multiplicacion de matrices (GEMM)...", end=" ")        z = torch.matmul(x, y)        # Sincronizacion para medir exito real (las ops de GPU son asincronas)        torch.cuda.synchronize()        print("OK")        print(f"Resultado shape: {z.shape}")        print(f"Dispositivo de salida: {z.device}")        print("\n[OK] PRUEBA DE COMPUTO COMPLETADA EXITOSAMENTE.")    except Exception as e:        print(f"\n[ERROR] DURANTE EL COMPUTO: {e}")        import traceback        traceback.print_exc()if __name__ == "__main__":    main()